const PocketBase = require("pocketbase/cjs");

async function main() {
  const args = process.argv.slice(2);

  // Parse --items <N> and --fail flags
  let itemsN = null;
  let failMode = false;
  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--items" && i + 1 < args.length) {
      itemsN = parseInt(args[i + 1], 10);
      i++;
    } else if (args[i] === "--fail") {
      failMode = true;
    }
  }

  if (itemsN === null || isNaN(itemsN) || itemsN < 0) {
    console.error("Usage: node app.js --items <N> [--fail]");
    process.exit(2);
  }

  const pbUrl = process.env.PB_URL;
  const pbAdminEmail = process.env.PB_ADMIN_EMAIL;
  const pbAdminPassword = process.env.PB_ADMIN_PASSWORD;
  const zealtRunId = process.env.ZEALT_RUN_ID;

  if (!pbUrl || !pbAdminEmail || !pbAdminPassword || !zealtRunId) {
    console.error("Missing required environment variables: PB_URL, PB_ADMIN_EMAIL, PB_ADMIN_PASSWORD, ZEALT_RUN_ID");
    process.exit(2);
  }

  const pb = new PocketBase(pbUrl);

  // Authenticate as admin
  await pb.collection("_superusers").authWithPassword(pbAdminEmail, pbAdminPassword);

  const batch = pb.createBatch();

  // Create the order record
  batch.collection("orders").create({
    customer: zealtRunId,
  });

  // Create N order_items. We'll use a sentinel value for the order field
  // that will be resolved by the batch transaction on the server side.
  // In PocketBase batch, we can reference results from prior batch entries
  // using the @request.<index>.data.id syntax.
  for (let i = 0; i < itemsN; i++) {
    batch.collection("order_items").create({
      order: "@request.0.data.id",
    });
  }

  // In --fail mode, add a request that will cause the batch to fail
  // (e.g., referencing a non-existent collection)
  if (failMode) {
    batch.collection("order_items").create({
      order: "@request.0.data.id",
      _non_existent_field_trigger_error: "intentional_failure_for_rollback_test",
    });
  }

  try {
    const results = await batch.send();

    if (failMode) {
      // Should not reach here — batch should have failed
      console.error("BATCH_ROLLED_BACK");
      process.exit(1);
    }

    // The first result (index 0) is the orders create response
    const orderResult = results[0];
    const orderId = orderResult.body.id;

    console.log(`ORDER:${orderId}`);
    process.exit(0);
  } catch (err) {
    if (failMode) {
      console.error("BATCH_ROLLED_BACK");
      process.exit(1);
    }
    console.error("Batch request failed:", err.message);
    process.exit(1);
  }
}

main();

